r_mwa_req_form_loan_norm_new_year_nest.sql:
select sc_lon_m_loan_history.loan_requestment_no ,sc_lon_m_loan_history.loan_type--ประเภท ,sc_lon_m_loan_history.loan_contract_no --สัญญาเงินกู้ ,sc_lon_m_loan_history.principal_of_loan --ยอดคงเหลือ ,sc_lon_m_loan_history.interest_amount--ดอกเบี้ย ,sc_lon_m_loan_history.clear_target--หักกลบ ,sc_lon_m_loan_history.principal_balance_of_loan + sc_lon_m_loan_history.interest_amount as total_clr --รวมหักกลบ ,sc_lon_m_loan_request_mpaid.paid_amount --คงเหลือรับสุทธิ
from sc_lon_m_loan_history ,sc_lon_m_loan_request_mpaid ,sc_lon_m_loan_request
where sc_lon_m_loan_history.loan_requestment_no = sc_lon_m_loan_request_mpaid.loan_requestment_no and sc_lon_m_loan_request.loan_requestment_no = sc_lon_m_loan_history.loan_requestment_no and clear_target = '1' and sc_lon_m_loan_history.loan_requestment_no = {0}
